def main():
    os.makedirs(OUTPUT_DIR, exist_ok=True)

    total = 0

    print("Appending CISA supplement...")
    cisa = generate_cisa_supplement()
    total += append_jsonl("cisa_stopransomware.jsonl", cisa)

    print("Appending Kaspersky supplement...")
    kaspersky = generate_kaspersky_supplement()
    total += append_jsonl("kaspersky_securelist.jsonl", kaspersky)

    print("Appending DFIR Report supplement...")
    dfir = generate_dfir_supplement()
    total += append_jsonl("dfir_report.jsonl", dfir)

    print("Appending SANS supplement...")
    sans = generate_sans_supplement()
    total += append_jsonl("sans_dfir.jsonl", sans)

    print(f"\nSupplemental examples generated: {total}")
    print(f"  CISA supplement:     {len(cisa)}")
    print(f"  Kaspersky supplement:{len(kaspersky)}")
    print(f"  DFIR supplement:     {len(dfir)}")
    print(f"  SANS supplement:     {len(sans)}")

    # Count totals
    for fname in ["cisa_stopransomware.jsonl", "kaspersky_securelist.jsonl",
                   "dfir_report.jsonl", "sans_dfir.jsonl"]:
        path = os.path.join(OUTPUT_DIR, fname)
        with open(path) as f:
            count = sum(1 for _ in f)
        print(f"  Total in {fname}: {count}")


if __name__ == "__main__":
    main()
